    auto Cin = x.size(1);
    auto H = x.size(2);
    auto W = x.size(3);
    auto Cout = weight.size(0);
    auto KH = weight.size(2);
    auto KW = weight.size(3);
    auto OH = H - KH + 1;
    auto OW = W - KW + 1;

    at::Tensor y = at::empty({N, Cout, OH, OW}, x.options());

    if (bias_opt.has_value() && bias_opt.value().defined()) {
        const at::Tensor& bias = bias_opt.value();
        EXEC_NPU_CMD(aclnnConv2dSubtractSubtractMishCustom, x, weight, bias, subtract_value_1, subtract_value_2, y);
    } else {
        // Create an empty bias tensor to keep call signature uniform
        at::Tensor empty_bias = at::empty({0}, x.options());
        EXEC_NPU_CMD(aclnnConv2dSubtractSubtractMishCustom, x, weight, empty_bias, subtract_value_1, subtract_value_2, y);
    }
    return y;
}
